// MessageModal.js
import React from "react";

const MessageModal = ({ show, title, message, type, isConfirmation, onConfirm, onClose, }) => {
  if (!show) return null;
  return (
    <>
      if (!show) return null;

return (
  <>
    <div  className="modal d-block" style={{ backgroundColor: "rgba(0,0,0,0.5)", zIndex: 99999, }} >
      <div className="modal-dialog modal-dialog-centered" style={{ transform: "translateY(-100px)" }}>
        <div className="modal-content border-0 shadow-lg" style={{ borderRadius: "15px" }} >
          <div className="modal-header border-0 pb-0">
            {/* <h5 className="modal-title fw-bold">
              {isConfirmation ? (
                <i className="fa fa-question-circle text-warning me-2"></i>
              ) : type === "success" ? (
                <i className="fa fa-check-circle text-success me-2"></i>
              ) : (
                <i className="fa fa-times-circle text-danger me-2"></i>
              )}
              {title}
            </h5> */}

            <button type="button" className="btn-close btn-sm" onClick={onClose} ></button>
          </div>

          <div className="modal-body text-center py-2">
            <label className="form-label col-form-label">{message}</label>
          </div>

          <div className="modal-footer border-0 justify-content-center">
            {isConfirmation ? (
              <>
                <button className="btn btn-outline-danger btn-sm px-4" onClick={onClose} ><i className="fa fa-times me-2"></i> No </button>
                <button className="btn btn-primary btn-sm px-4" onClick={() => { onConfirm(); onClose(); }} ><i className="fa fa-check me-2"></i> Yes </button>
              </>
            ) : (
                <button className="btn btn-primary btn-sm px-4" onClick={onClose} ><i className="fa fa-check me-2"></i> OK </button>
            )}
          </div>
        </div>
      </div>
    </div>
  </>
);
    </>
  );
};

export default MessageModal;
